function handleSubmit(form) {
  const result = processOrder(form);
  saveUser(result);
  return result;
}

function readPort(raw) {
  console.log(raw);
  const cfg = JSON.parse(raw);
  return parseInt(cfg.port, 10);
}

function registerUser(form) {
  const email = normalizeEmail(form.email);
  return validateUser(email);
}

function main(argv) {
  const opts = parseArgs(argv);
  return opts;
}

function countLogs(db, level) {
  const q = `SELECT COUNT(*) FROM logs WHERE level = ${level}`;
  return db.query(q);
}

function dispatch(handlers, evt) {
  const fn = handlers[evt.type];
  fn(evt);
}

function match(s) {
  const re = /Foo(x)/;
  return re.test(s);
}
